"use client";

import { useEffect, useRef } from "react";
import * as fabric from "fabric";
import { useEditor } from "./EditorContext";
import { cn } from "@/lib/utils";

export default function Canvas() {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const { setCanvas, setSelectedObject } = useEditor();

  useEffect(() => {
    if (!canvasRef.current || !containerRef.current) return;

    // Initialize Fabric Canvas
    const fabricCanvas = new fabric.Canvas(canvasRef.current, {
      width: 800,
      height: 800,
      backgroundColor: "#ffffff",
      preserveObjectStacking: true,
    });

    setCanvas(fabricCanvas);

    // Event Listeners
    fabricCanvas.on("selection:created", (options) => {
      setSelectedObject(options.selected[0] || null);
    });

    fabricCanvas.on("selection:updated", (options) => {
      setSelectedObject(options.selected[0] || null);
    });

    fabricCanvas.on("selection:cleared", () => {
      setSelectedObject(null);
    });

    // Initial Content
    const title = new fabric.FabricText("Ad Title Here", {
      left: 100,
      top: 100,
      fontSize: 48,
      fill: "#000000",
      fontWeight: "bold",
    });
    
    const subtitle = new fabric.FabricText("Amazing product features go here", {
      left: 100,
      top: 180,
      fontSize: 24,
      fill: "#666666",
    });

    fabricCanvas.add(title, subtitle);
    fabricCanvas.renderAll();

    return () => {
      fabricCanvas.dispose();
      setCanvas(null);
    };
  }, [setCanvas, setSelectedObject]);

  return (
    <div ref={containerRef} className="relative flex-1 overflow-auto bg-zinc-100 dark:bg-zinc-900 shadow-inner flex items-center justify-center p-12">
      <div className="bg-white shadow-2xl dark:shadow-none border border-zinc-200 dark:border-zinc-800 rounded-sm">
        <canvas ref={canvasRef} />
      </div>
      
      {/* Zoom / Info Overlay */}
      <div className="absolute bottom-6 right-6 flex items-center bg-white/90 dark:bg-zinc-800/90 backdrop-blur-md border border-zinc-200 dark:border-zinc-700 rounded-lg px-4 py-2 gap-4 shadow-sm">
        <span className="text-xs font-mono text-zinc-500">800 x 800 px</span>
      </div>
    </div>
  );
}
